          "graphique": "<svg font-family=\"-apple-system,sans-serif\" font-size=\"13\" height=\"244\" viewbox=\"0 0 340 260\" width=\"320\" xmlns=\"http://www.w3.org/2000/svg\">\n<!-- Points :\n             O=(20,220), N=(130,110), S=(200,20), U=(240,120), E=(185,180), D=(300,240) -->\n<!-- Traits de la figure -->\n<!-- O-N-S -->\n<line stroke=\"#333\" stroke-width=\"1.5\" x1=\"20\" x2=\"130\" y1=\"220\" y2=\"110\"></line>\n<line stroke=\"#333\" stroke-width=\"1.5\" x1=\"130\" x2=\"200\" y1=\"110\" y2=\"20\"></line>\n<!-- O-E-D -->\n<line stroke=\"#333\" stroke-width=\"1.5\" x1=\"20\" x2=\"185\" y1=\"220\" y2=\"180\"></line>\n<line stroke=\"#333\" stroke-width=\"1.5\" x1=\"185\" x2=\"300\" y1=\"180\" y2=\"240\"></line>\n<!-- N-U -->\n<line stroke=\"#333\" stroke-width=\"1.5\" x1=\"130\" x2=\"240\" y1=\"110\" y2=\"120\"></line>\n<!-- S-D -->\n<line stroke=\"#333\" stroke-width=\"1.5\" x1=\"200\" x2=\"300\" y1=\"20\" y2=\"240\"></line>\n<!-- N-D et U-O (diagonales) -->\n<line stroke=\"#333\" stroke-width=\"1.2\" x1=\"130\" x2=\"300\" y1=\"110\" y2=\"240\"></line>\n<line stroke=\"#333\" stroke-width=\"1.2\" x1=\"240\" x2=\"20\" y1=\"120\" y2=\"220\"></line>\n<!-- Marques égalité (croix rouges sur ON et SU) -->\n<!-- Milieu ON ≈ (75,165) -->\n<line stroke=\"#EF4444\" stroke-width=\"2\" x1=\"71\" x2=\"79\" y1=\"169\" y2=\"161\"></line>\n<line stroke=\"#EF4444\" stroke-width=\"2\" x1=\"71\" x2=\"79\" y1=\"161\" y2=\"169\"></line>\n<!-- Milieu SU ≈ (220,70) -->\n<line stroke=\"#EF4444\" stroke-width=\"2\" x1=\"166\" x2=\"174\" y1=\"66\" y2=\"58\"></line>\n<line stroke=\"#EF4444\" stroke-width=\"2\" x1=\"166\" x2=\"174\" y1=\"58\" y2=\"66\"></line>\n<!-- Points -->\n<circle cx=\"20\" cy=\"220\" fill=\"#333\" r=\"3\"></circle>\n<circle cx=\"130\" cy=\"110\" fill=\"#333\" r=\"3\"></circle>\n<circle cx=\"200\" cy=\"20\" fill=\"#333\" r=\"3\"></circle>\n<circle cx=\"240\" cy=\"120\" fill=\"#333\" r=\"3\"></circle>\n<circle cx=\"185\" cy=\"180\" fill=\"#333\" r=\"3\"></circle>\n<circle cx=\"300\" cy=\"240\" fill=\"#333\" r=\"3\"></circle>\n<!-- Labels -->\n<text fill=\"#333\" font-weight=\"600\" x=\"6\" y=\"224\">O</text>\n<text fill=\"#333\" font-weight=\"600\" x=\"120\" y=\"105\">N</text>\n<text fill=\"#333\" font-weight=\"600\" x=\"198\" y=\"14\">S</text>\n<text fill=\"#333\" font-weight=\"600\" x=\"246\" y=\"118\">U</text>\n<text fill=\"#333\" font-weight=\"600\" x=\"188\" y=\"196\">E</text>\n<text fill=\"#333\" font-weight=\"600\" x=\"306\" y=\"244\">D</text>\n<!-- Cotes à droite -->\n<text fill=\"var(--muted)\" font-size=\"12\" x=\"256\" y=\"60\">ON = 6 cm</text>\n<text fill=\"var(--muted)\" font-size=\"12\" x=\"256\" y=\"80\">SU = 5 cm</text>\n<text fill=\"var(--muted)\" font-size=\"12\" x=\"256\" y=\"100\">UD = 6 cm</text>\n</svg>"
