          "graphique": "<svg font-family=\"-apple-system,sans-serif\" font-size=\"12\" height=\"112\" viewbox=\"0 0 300 120\" width=\"280\" xmlns=\"http://www.w3.org/2000/svg\">\n<!-- Urne -->\n<ellipse cx=\"70\" cy=\"38\" fill=\"#e8e8e8\" rx=\"36\" ry=\"10\" stroke=\"#555\" stroke-width=\"1.2\"></ellipse>\n<path d=\"M34,38 Q20,90 34,100 Q70,112 106,100 Q120,90 106,38\" fill=\"#f5f5f5\" stroke=\"#555\" stroke-width=\"1.2\"></path>\n<ellipse cx=\"70\" cy=\"100\" fill=\"#e8e8e8\" rx=\"36\" ry=\"10\" stroke=\"#555\" stroke-width=\"1.2\"></ellipse>\n<!-- boules rouges (4) -->\n<circle cx=\"52\" cy=\"72\" fill=\"#EF4444\" r=\"9\" stroke=\"#c0392b\" stroke-width=\"1\"></circle>\n<circle cx=\"70\" cy=\"80\" fill=\"#EF4444\" r=\"9\" stroke=\"#c0392b\" stroke-width=\"1\"></circle>\n<circle cx=\"55\" cy=\"56\" fill=\"#EF4444\" r=\"8\" stroke=\"#c0392b\" stroke-width=\"1\"></circle>\n<circle cx=\"78\" cy=\"62\" fill=\"#EF4444\" r=\"8\" stroke=\"#c0392b\" stroke-width=\"1\"></circle>\n<!-- boules bleues (6) -->\n<circle cx=\"88\" cy=\"76\" fill=\"#3B82F6\" r=\"9\" stroke=\"#1d4ed8\" stroke-width=\"1\"></circle>\n<circle cx=\"60\" cy=\"90\" fill=\"#3B82F6\" r=\"8\" stroke=\"#1d4ed8\" stroke-width=\"1\"></circle>\n<circle cx=\"82\" cy=\"50\" fill=\"#3B82F6\" r=\"8\" stroke=\"#1d4ed8\" stroke-width=\"1\"></circle>\n<circle cx=\"94\" cy=\"60\" fill=\"#3B82F6\" r=\"7\" stroke=\"#1d4ed8\" stroke-width=\"1\"></circle>\n<circle cx=\"44\" cy=\"85\" fill=\"#3B82F6\" r=\"7\" stroke=\"#1d4ed8\" stroke-width=\"1\"></circle>\n<circle cx=\"96\" cy=\"88\" fill=\"#3B82F6\" r=\"7\" stroke=\"#1d4ed8\" stroke-width=\"1\"></circle>\n<text fill=\"var(--muted)\" font-size=\"10\" text-anchor=\"middle\" x=\"70\" y=\"118\">4 rouges + 6 bleues</text>\n<!-- Séparateur -->\n<line stroke=\"rgba(0,0,0,.1)\" stroke-dasharray=\"4,3\" stroke-width=\"1\" x1=\"150\" x2=\"150\" y1=\"10\" y2=\"110\"></line>\n<!-- Dé (cube simplifié) -->\n<rect fill=\"white\" height=\"60\" rx=\"8\" stroke=\"#555\" stroke-width=\"1.5\" width=\"60\" x=\"185\" y=\"30\"></rect>\n<!-- points du dé face 4 -->\n<circle cx=\"200\" cy=\"48\" fill=\"#333\" r=\"5\"></circle>\n<circle cx=\"230\" cy=\"48\" fill=\"#333\" r=\"5\"></circle>\n<circle cx=\"200\" cy=\"72\" fill=\"#333\" r=\"5\"></circle>\n<circle cx=\"230\" cy=\"72\" fill=\"#333\" r=\"5\"></circle>\n<text fill=\"var(--muted)\" font-size=\"10\" text-anchor=\"middle\" x=\"215\" y=\"108\">faces 1 à 6</text>\n</svg>"
